&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;div style=&#34;display: flex;&#34;&gt;
&lt;img data-src=&#34;https://img.shields.io/npm/v/@coloration/hooks.svg&#34; alt=&#34;version&#34;&gt;
